<template>
  <el-form ref="form" :model="form" class="box-set" label-width="100px">
    <el-card header="活動商品訊息" shadow="never">
      <el-form-item label="活動封麵">
        <div class="frm-tips">
          文件格式為bmp、png、jpeg、jpg或gif，大小不超過2M（建議尺寸：500px * 500px）
        </div>
        <div>
          <imgBox :img-url="wximageurl + form.pics" @click="handleImgChange" />
        </div>
        <imgPicker
          :dialog-visible="imgDialog"
          :sc-status="isGetImage"
          @chooseImg="pickImg"
          @closeImgDialog="closeImgDialog"
        />
      </el-form-item>
      <el-form-item label="拚團商品">
        <el-row :gutter="20">
          <el-col :span="20">
            <p class="frm-tips" />
            <div class="logo-box" @click="changeItem">
              <div class="bran-img">
                <div v-if="goods.pics" class="groups-addgoods">
                  <img :src="wximageurl + goods.pics[0]" class="groups-goodspic">
                  <div class="gooups-goodsmsg">
                    <div>{{ goods.itemName }}</div>
                    <div>原價：{{ goods.price }}</div>
                    <div v-if="goods.item_type == 'normal'">庫存：{{ goods.store }}</div>
                  </div>
                </div>
                <div v-else tabindex="0" class="el-upload el-upload--picture-card">
                  <i class="el-icon-plus" />
                </div>
              </div>
              <!-- <el-button size="small" type="primary" @click="changeItem">選擇商品</el-button> -->
            </div>
          </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="活動名稱" prop="act_name" :rules="rules.act_name">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-input v-model="form.act_name" :maxlength="30" placeholder="拚團活動名稱" />
          </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="活動時間" prop="date" :rules="rules.date">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-date-picker
              v-model="form.date"
              type="datetimerange"
              range-separator="至"
              start-placeholder="生效時間"
              end-placeholder="過期時間"
              value-format="yyyy-MM-dd HH:mm:ss"
              :default-time="['00:00:00', '23:59:59']"
            />
          </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="拚團庫存" prop="store" :rules="rules.store">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-input v-model="form.store" placeholder="" />
          </el-col>
          <el-col :span="2"> 件 </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="拚團價格" prop="act_price" :rules="rules.act_price">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-input v-model="form.act_price" placeholder=""> 元 </el-input>
          </el-col>
          <el-col :span="2"> 元 </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="成團人數" prop="person_num" :rules="rules.person_num">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-input v-model="form.person_num" placeholder=""> 人 </el-input>
          </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="成團時效" prop="limit_time" :rules="rules.limit_time">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-input v-model="form.limit_time" placeholder="小時" />
          </el-col>
          <el-col :span="2"> 小時 </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="拚團限制" prop="limit_buy_num" :rules="rules.limit_buy_num">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-input v-model="form.limit_buy_num" placeholder="" />
            <p class="frm-tips">(限制一人隻能參加X次活動，為0表示無限制)</p>
          </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="成團機器人">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-switch v-model="form.robot" active-value="1" inactive-value="0" />
            <p class="frm-tips">
              (開啟成團機器人後，成團時效內人數未滿的團，系統將會使用機器人湊滿人數，使該團成團。商家隻需對真實訂單進行出貨處理。)
            </p>
          </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="湊團">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-switch v-model="form.rig_up" active-value="1" inactive-value="0" />
            <p class="frm-tips">
              (開啟湊團後，消費者可以在拚團商品詳情頁看到未成團的團列表，可選擇其中一個參團。有效提高成團成功率)
            </p>
          </el-col>
        </el-row>
      </el-form-item>
      <el-form-item v-if="goods.item_type == 'normal'" label="包郵">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-switch v-model="form.free_post" active-value="1" inactive-value="0" />
            <p class="frm-tips">(如果不開啟包郵，那麼運費按照商品的運費模版計算運費)</p>
          </el-col>
        </el-row>
      </el-form-item>
      <el-form-item label="分享描述" prop="share_desc" :rules="rules.share_desc">
        <el-row :gutter="20">
          <el-col :span="12">
            <el-input
              v-model="form.share_desc"
              :maxlength="25"
              placeholder="請輸入拚團活動分享文字"
            >
              （最多25個字）
            </el-input>
          </el-col>
        </el-row>
      </el-form-item>
    </el-card>
    <div class="content-center">
      <el-button @click.native="handleCancel"> 返回 </el-button>
      <el-button v-if="true == show" type="primary" @click.prevent="submitItemsAction('form')">
        儲存
      </el-button>
    </div>
    <el-dialog title="選擇商品" :visible.sync="goodsDialogVisible" center>
      <!-- <el-button-group class="tab-group">
        <el-button
          class="tab-btn"
          @click="changeGoods('every')"
          :class="goodsTypeTitle === '服務類商品' ? 'on' : ''"
          >服務類商品</el-button
        >
        <el-button
          class="tab-btn"
          @click="changeGoods('normal')"
          :class="goodsTypeTitle === '實體類商品' ? 'on' : ''"
          >實體類商品</el-button
        >
      </el-button-group> -->
      <el-row class="content-bottom-padded" :gutter="20">
        <el-col :span="12">
          <el-input v-model="itemsParams.keywords" placeholder="商品名稱">
            <el-button slot="append" icon="el-icon-search" @click="goodsSearch" />
          </el-input>
        </el-col>
      </el-row>
      <el-table v-loading="itemsLoading" :data="itemsList" style="width: 100%" border height="500">
        <el-table-column prop="itemName" label="商品名稱" />
        <el-table-column label="縮略圖">
          <template slot-scope="scope">
            <img width="20" :src="wximageurl + scope.row.pics[0]">
          </template>
        </el-table-column>
        <el-table-column prop="price" label="售價" :formatter="priceformatter" />
        <el-table-column prop="itemName" label="狀態">
          <template slot-scope="scope">
            <el-button
              v-if="form.goods_id != scope.row.itemId"
              type="text"
              @click="chooseItem(scope.row)"
            >
              選擇
            </el-button>
            <span v-else>已選擇</span>
          </template>
        </el-table-column>
      </el-table>
      <div v-if="itemsTotalCount > itemsParams.pageSize" class="content-center content-top-padded">
        <el-pagination
          layout="prev, pager, next"
          :current-page.sync="itemsParams.page"
          :total="itemsTotalCount"
          :page-size="itemsParams.pageSize"
          @current-change="goodsHandleCurrentChange"
        />
      </div>
      <span slot="footer" class="dialog-footer">
        <el-button @click="goodsDialogVisible = false">關 閉</el-button>
        <el-button type="primary" @click="goodsDialogVisible = false">確 定</el-button>
      </span>
    </el-dialog>
  </el-form>
</template>
<script>
import { uploadMaterial } from '../../../api/wechat'
import { getItemsList } from '../../../api/goods'
import { getDefaultCurrency } from '../../../api/company'
import { createGroupActivity, updateGroupActivity, getGroupsInfo } from '../../../api/promotions'
import imgPicker from '../../../components/imageselect'
import imgBox from '@/components/element/imgBox'

export default {
  inject: ['refresh'],
  components: {
    imgPicker,
    imgBox
  },
  data() {
    return {
      show: true,
      itemsLoading: false,
      groups_activity_id: '',
      form: {
        pics: '',
        goods_id: '',
        act_name: '',
        date: '',
        store: '',
        act_price: '',
        person_num: '',
        limit_time: '',
        limit_buy_num: '',
        robot: '1',
        rig_up: '1',
        free_post: '1',
        share_desc: ''
      },
      goods: {},
      itemsList: [],
      itemsParams: {
        page: 1,
        pageSize: 20,
        // consume_type: 'every',
        item_type: 'normal',
        nospec: true,
        keywords: ''
      },
      itemsTotalCount: 0,
      logo_url: '',
      dialogVisible: false,
      dialogImageUrl: '',
      goodsDialogVisible: false,
      rules: {
        act_name: [{ required: true, message: '請輸入拚團活動名稱' }],
        date: [{ required: true, message: '請輸入活動時間' }],
        store: [
          { required: true, message: '請輸入拚團庫存' },
          { pattern: /^[1-9]\d{0,4}$/, message: '庫存最少為1，最多99999' }
        ],
        act_price: [
          { required: true, message: '請輸入拚團價格' },
          { pattern: /^(?=.*[1-9])\d+(\.\d{1,2})?$/, message: '拚團價格最少0.01' }
        ],
        person_num: [
          { required: true, message: '請輸入成團人數' },
          { pattern: /^([2-9]|[1-9]\d{1})$/, message: '最少2人成團,最多99人成團' }
        ],
        limit_time: [
          { required: true, message: '請輸入成團時效' },
          { pattern: /^[1-9]\d{0,1}$/, message: '成團時效至少1小時，最多99小時' }
        ],
        limit_buy_num: [
          { required: true, message: '請輸入限購數量' },
          { pattern: /^\d{0,2}$/, message: '最多99' }
        ],
        share_desc: [{ required: true, message: '請輸入分享描述' }]
      },
      imgDialog: false,
      isGetImage: false,
      currency: {},
      cursymbol: 'NT$',
      goodsTypeTitle: '服務類商品'
    }
  },
  mounted() {
    if (this.$route.query.show) {
      this.show = false
    }
    if (this.$route.params.groups_id) {
      this.groups_activity_id = this.$route.params.groups_id
      this.getGroupsInfo()
    }
    this.getCurrencyInfo()
  },
  methods: {
    submitItemsAction(formName) {
      const that = this
      this.$refs[formName].validate((valid) => {
        if (valid) {
          if (!this.form.pics) {
            this.$message.error('請上傳活動封麵')
            return false
          }
          if (!this.form.goods_id) {
            this.$message.error('請選擇商品')
            return false
          }
          if (this.groups_activity_id) {
            updateGroupActivity(this.groups_activity_id, this.form).then((res) => {
              if (res.data.data) {
                this.$message({
                  message: '更新成功',
                  type: 'success',
                  duration: 2 * 1000,
                  onClose() {
                    that.refresh()
                    that.$router.go(-1)
                  }
                })
              }
            })
          } else {
            createGroupActivity(this.form).then((res) => {
              if (res.data.data) {
                this.$message({
                  message: '新增成功',
                  type: 'success',
                  duration: 2 * 1000,
                  onClose() {
                    that.refresh()
                    that.$router.go(-1)
                  }
                })
              }
            })
          }
        } else {
          return false
        }
      })
    },
    handleCancel() {
      this.$router.go(-1)
    },
    //老的活動封麵上傳
    // handlePicChange (file) {
    //   let that = this
    //   if (file && file.raw) {
    //     if (file.raw.type !== 'image/jpeg' && file.raw.type !== 'image/png') {
    //       that.$message.error('上傳圖片隻能是 JPG 或者 PNG 格式!')
    //     }
    //     if (file.raw.size / 1024 / 1024 > 5) {
    //       that.$message.error('上傳圖片大小不能超過 5MB!')
    //     }
    //   }

    //   let params = {isUploadFile: true, file: file.raw, type: 'image'}
    //   uploadMaterial(params).then(res => {
    //     file.url = this.wximageurl + res.data.data.url
    //     that.form.pics = res.data.data.url
    //     that.logo_url = file.url
    //   })
    // },
    changeItem() {
      this.goodsDialogVisible = true
      this.getGoodsList()
    },
    chooseItem(row) {
      this.goodsDialogVisible = false
      this.goods = row
      this.goods.price = this.goods.price / 100
      this.form.goods_id = row.itemId
    },
    goodsHandleCurrentChange(val) {
      this.itemsParams.page = val
      this.getGoodsList()
    },
    goodsSearch() {
      this.getGoodsList()
    },
    getGoodsList() {
      this.itemsLoading = true

      let where = this.itemsParams
      where.approve_status = ['onsale', 'offline_sale']
      where.is_gift = false
      getItemsList(where)
        .then((response) => {
          this.itemsLoading = false
          this.itemsList = response.data.data.list
          this.itemsTotalCount = response.data.data.total_count
        })
        .catch((error) => {
          this.itemsLoading = false
          this.$message({
            type: 'error',
            message: '獲取商品列表列表訊息出錯'
          })
        })
    },
    getGroupsInfo() {
      getGroupsInfo(this.groups_activity_id)
        .then((response) => {
          this.form = response.data.data
          this.form.act_price = this.form.act_price / 100
          this.form.goods.price = this.form.goods.price / 100
          this.form.goods.market_price = this.form.goods.market_price / 100
          this.form.date = [
            new Date(response.data.data.begin_time * 1000),
            new Date(response.data.data.end_time * 1000)
          ]
          this.form.robot = response.data.data.robot == 1 ? '1' : '0'
          this.form.rig_up = response.data.data.rig_up == 1 ? '1' : '0'
          this.form.free_post = response.data.data.free_post == 1 ? '1' : '0'
          this.logo_url = this.wximageurl + response.data.data.pics
          this.goods = response.data.data.goods
        })
        .catch((error) => {
          this.$message({
            type: 'error',
            message: '獲取拚團活動詳情失敗'
          })
        })
    },
    priceformatter(row, column) {
      return this.cursymbol + row.price / 100
    },
    getCurrencyInfo() {
      getDefaultCurrency().then((res) => {
        this.currency = res.data.data
        this.cursymbol = this.currency.symbol
      })
    },
    //活動封麵
    handleImgChange() {
      this.imgDialog = true
      this.isGetImage = true
    },
    pickImg(data) {
      console.log(data.url)
      this.form.pics = data.url
      console.log(this.form.pics)
      this.imgDialog = false
    },
    closeImgDialog() {
      this.imgDialog = false
    },
    changeGoods(type) {
      switch (type) {
        case 'every':
          this.$set(this.itemsParams, 'consume_type', 'every')
          this.$delete(this.itemsParams, 'item_type')
          this.goodsTypeTitle = '服務類商品'
          break
        case 'normal':
          this.$set(this.itemsParams, 'item_type', 'normal')
          this.$delete(this.itemsParams, 'consume_type')
          this.goodsTypeTitle = '實體類商品'
          break
      }
      this.getGoodsList()
    }
  }
}
</script>

